import FeatureGates from '@atlaskit/feature-gate-js-client';
function isStringList(value) {
  return Array.isArray(value) && value.every(function (item) {
    return typeof item === 'string';
  });
}
var STRING_LIST_CONFIG_KEY = 'value';

